module SixDerivSpectrumResults

# ═══════════════════════════════════════════════════════════════════════════
# Flat-space form factors (Buoninfante Eq. 2.13)
# ═══════════════════════════════════════════════════════════════════════════

"""Spin-2 form factor: f₂(z) = 1 − (α₂/κ)z − (β₂/κ)z²"""
f₂(z; κ, α₂, β₂) = 1 - (α₂/κ)*z - (β₂/κ)*z^2

"""Spin-0 form factor: f₀(z) = 1 + (6α₁+2α₂)z/κ + (6β₁+2β₂)z²/κ"""
f₀(z; κ, α₁, α₂, β₁, β₂) = 1 + (6α₁ + 2α₂)*z/κ + (6β₁ + 2β₂)*z^2/κ

"""Form factor coefficients: (c₁, c₂) where f(z) = 1 + c₁z + c₂z²"""
f₂_coeffs(; κ, α₂, β₂) = (-α₂/κ, -β₂/κ)
f₀_coeffs(; κ, α₁, α₂, β₁, β₂) = ((6α₁ + 2α₂)/κ, (6β₁ + 2β₂)/κ)

# ═══════════════════════════════════════════════════════════════════════════
# Pole structure
# ═══════════════════════════════════════════════════════════════════════════

"""Find massive poles of form factor f(z) = 1 + c₁z + c₂z²."""
function find_poles(c₁, c₂)
    if abs(c₂) < 1e-15
        abs(c₁) < 1e-15 && return Complex{Float64}[]
        return [complex(-1.0/c₁)]
    end
    disc = c₁^2 - 4c₂
    if disc >= 0
        z₁ = (-c₁ + sqrt(disc)) / (2c₂)
        z₂ = (-c₁ - sqrt(disc)) / (2c₂)
        return [complex(z₁), complex(z₂)]
    else
        re = -c₁ / (2c₂)
        im_part = sqrt(-disc) / (2c₂)
        return [complex(re, im_part), complex(re, -im_part)]
    end
end

"""Residues of 1/(z·f(z)) at the massive poles."""
function pole_residues(poles, c₁, c₂)
    [1.0 / (z * (c₁ + 2c₂*z)) for z in poles]
end

# ═══════════════════════════════════════════════════════════════════════════
# Stelle limits (β₁ = β₂ = 0)
# ═══════════════════════════════════════════════════════════════════════════

"""Stelle massive spin-2 mass: m²_g = κ/α₂"""
stelle_m2_spin2(; κ, α₂) = κ / α₂

"""Stelle spin-0 mass: m²_s = −κ/(6α₁+2α₂)"""
stelle_m2_spin0(; κ, α₁, α₂) = -κ / (6α₁ + 2α₂)

# ═══════════════════════════════════════════════════════════════════════════
# de Sitter spectrum: Bueno-Cano parameters
# ═══════════════════════════════════════════════════════════════════════════

"""
Bueno-Cano parameters (a,b,c,e) for each Lagrangian term.
Convention: Λ is TGR's cosmological constant (R̄_{μν} = Λg_{μν}).
Bueno-Cano uses Λ_BC = Λ/3.
Returns NamedTuple (a, b, c, e).
"""
const BC_FUNCTIONS = Dict(
    :EH      => (κ, Λ) -> (a=0.0, b=0.0, c=0.0, e=Float64(κ)),
    :R2      => (α₁, Λ) -> (a=0.0, b=2α₁, c=0.0, e=8α₁*Λ),
    :RicSq   => (α₂, Λ) -> (a=0.0, b=0.0, c=2α₂, e=2α₂*Λ),
    :R3      => (γ, Λ) -> (a=0.0, b=6γ*Λ, c=0.0, e=24γ*Λ^2),
    :RRicSq  => (γ, Λ) -> (a=0.0, b=γ*Λ, c=2γ*Λ, e=6γ*Λ^2),
    :Ric3    => (γ, Λ) -> (a=0.0, b=0.0, c=1.5γ*Λ, e=1.5γ*Λ^2),
    :RRiem2  => (γ, Λ) -> (a=4γ*Λ, b=2γ*Λ/3, c=0.0, e=4γ*Λ^2),
    :RicRiem2=> (γ, Λ) -> (a=γ*Λ, b=0.0, c=2γ*Λ/3, e=γ*Λ^2),
    :Riem3   => (γ, Λ) -> (a=2γ*Λ, b=0.0, c=0.0, e=2γ*Λ^2/3),
)

"""
Dimensionless BC coefficients (ā,b̄,c̄,ē) for cubic invariants.
Contribution is γᵢ·(āΛ, b̄Λ, c̄Λ, ēΛ²).
"""
const BC_CUBIC_COEFFICIENTS = Dict(
    :I1_R3      => (a=0,   b=6,   c=0,   e=24),
    :I2_RRicSq  => (a=0,   b=1,   c=2,   e=6),
    :I3_Ric3    => (a=0,   b=0,   c=3//2, e=3//2),
    :I4_RRiem2  => (a=4,   b=2//3, c=0,   e=4),
    :I5_RicRiem2=> (a=1,   b=0,   c=2//3, e=1),
    :I6_Riem3   => (a=2,   b=0,   c=0,   e=2//3),
)

"""Physical dS spectrum from total BC parameters."""
function dS_physical_spectrum(a, b, c, e, Λ)
    Λ_BC = Λ / 3
    κ_eff_inv = 4e - 8Λ_BC * a
    m2_g = abs(2a + c) > 1e-15 ? (-e + 2Λ_BC * a) / (2a + c) : Inf
    m2_s = abs(2a + 4c + 12b) > 1e-15 ? (2e - 4Λ_BC*(a + 4b + c)) / (2a + 4c + 12b) : Inf
    (κ_eff_inv=κ_eff_inv, m2_graviton=m2_g, m2_scalar=m2_s)
end

# ═══════════════════════════════════════════════════════════════════════════
# SVT quadratic form structure (scalar sector)
# ═══════════════════════════════════════════════════════════════════════════

"""
Tensor sector: M_TT(p²) = κp² · f₂(p²) = κp² − α₂p⁴ − β₂p⁶

Scalar sector (2×2 in Bardeen variables Φ,ψ):
  M_ΦΦ = (α₁+β₁p²)·4k⁴ + (α₂+β₂p²)·2k⁴  (inverted sign, see svt_quadratic.jl)
  M_Φψ = −2κk² + higher-derivative terms
  M_ψψ = κ(2k²−6ω²) + higher-derivative terms

det(M_scalar) vanishes at f₀(p²) = 0 roots.
Vector sector vanishes identically (diffeomorphism invariance).
"""
const SVT_STRUCTURE = (
    tensor_fields = [:hTT],
    scalar_fields = [:Phi, :psi],
    vector_vanishes = true,
    tensor_formula = "M_TT = κp²f₂(p²)",
    scalar_det_formula = "det(M) ~ k⁴ · f₀(p²) · (polynomial in ω²,k²)",
)

